from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a building into a single fluent sentence.
    """
    if not triples:
        return ""

    # Build a map of all subjects to their triples
    subject_triples = {}
    for t in triples:
        if t.subject not in subject_triples:
            subject_triples[t.subject] = []
        subject_triples[t.subject].append(t)

    # Find the main building (subject with most triples or first one)
    main_subject = max(subject_triples.keys(), key=lambda s: len(subject_triples[s]))
    main_triples = subject_triples[main_subject]

    # Collect all predicate types and their objects
    predicate_map = {}
    for t in main_triples:
        if t.predicate not in predicate_map:
            predicate_map[t.predicate] = []
        predicate_map[t.predicate].append(t.object)

    # Build location chain (handle isPartOf, country, state, region, location hierarchically)
    location_parts = []
    if "location" in predicate_map:
        location_parts.append(f"located at {predicate_map['location'][0]}")
    if "isPartOf" in predicate_map:
        for obj in predicate_map["isPartOf"]:
            location_parts.append(f"which is part of {obj}")
    if "state" in predicate_map:
        location_parts.append(f"within {predicate_map['state'][0]}")
    if "region" in predicate_map:
        location_parts.append(f"in the {predicate_map['region'][0]} region")
    if "country" in predicate_map:
        location_parts.append(f"country of {predicate_map['country'][0]}")
    if "address" in predicate_map:
        location_parts.append(f"at address {predicate_map['address'][0]}")

    # Build design/construction information
    design_parts = []
    if "architect" in predicate_map:
        design_parts.append(f"designed by {predicate_map['architect'][0]}")
    if "architecturalStyle" in predicate_map:
        design_parts.append(f"featuring {predicate_map['architecturalStyle'][0]}")
    if "developer" in predicate_map:
        design_parts.append(f"developed by {predicate_map['developer'][0]}")
    if "owner" in predicate_map:
        design_parts.append(f"owned by {predicate_map['owner'][0]}")
    if "tenant" in predicate_map:
        design_parts.append(f"with tenants including {predicate_map['tenant'][0]}")
    if "currentTenants" in predicate_map:
        design_parts.append(f"currently housing {predicate_map['currentTenants'][0]}")

    # Build construction details
    construction_parts = []
    if "buildingType" in predicate_map:
        construction_parts.append(f"a {predicate_map['buildingType'][0]}")
    if "height" in predicate_map:
        construction_parts.append(f"standing {predicate_map['height'][0]}")
    if "floorCount" in predicate_map:
        construction_parts.append(f"with {predicate_map['floorCount'][0]} floors")
    if "numberOfRooms" in predicate_map:
        construction_parts.append(f"containing {predicate_map['numberOfRooms'][0]} rooms")
    if "cost" in predicate_map:
        construction_parts.append(f"at a cost of {predicate_map['cost'][0]}")
    if "floorArea" in predicate_map:
        construction_parts.append(f"covering {predicate_map['floorArea'][0]}")
    if "bedCount" in predicate_map:
        construction_parts.append(f"with {predicate_map['bedCount'][0]} beds")
    if "yearOfConstruction" in predicate_map:
        construction_parts.append(f"built in {predicate_map['yearOfConstruction'][0]}")
    if "buildingStartDate" in predicate_map:
        construction_parts.append(f"construction began in {predicate_map['buildingStartDate'][0]}")
    if "completionDate" in predicate_map:
        construction_parts.append(f"completed in {predicate_map['completionDate'][0]}")
    if "inaugurationDate" in predicate_map:
        construction_parts.append(f"inaugurated on {predicate_map['inaugurationDate'][0]}")

    # Build other information
    other_parts = []
    for pred in ["governingBody", "leader", "governmentType", "capital", "currency", "language", "ethnicGroup", "demonym", "formerName", "origin", "significantBuilding", "significantProject", "keyPerson", "postalCode", "website", "foundationPlace", "deathPlace", "birthPlace", "NationalRegisterOfHistoricPlacesReferenceNumber", "addedToTheNationalRegisterOfHistoricPlaces", "architecture"]:
        if pred in predicate_map:
            if pred == "formerName":
                other_parts.append(f"formerly known as {predicate_map[pred][0]}")
            elif pred == "website":
                other_parts.append(f"website at {predicate_map[pred][0]}")
            elif pred in ["NationalRegisterOfHistoricPlacesReferenceNumber", "addedToTheNationalRegisterOfHistoricPlaces"]:
                other_parts.append(f"registered as {predicate_map[pred][0]}")
            else:
                other_parts.append(f"{pred.replace('_', ' ').lower()}: {predicate_map[pred][0]}")

    # Construct the sentence with proper flow
    sentence_parts = []
    sentence_parts.append(main_subject)

    # Add type if available
    if "buildingType" in predicate_map:
        sentence_parts.append(f"is a {predicate_map['buildingType'][0]}")
    else:
        sentence_parts.append("is a building")

    # Add construction details
    if construction_parts:
        sentence_parts.append(f", {', '.join(construction_parts)}")

    # Add design information
    if design_parts:
        sentence_parts.append(f", {', '.join(design_parts)}")

    # Add location information
    if location_parts:
        sentence_parts.append(f", {', '.join(location_parts)}")

    # Add other information
    if other_parts:
        sentence_parts.append(f", {', '.join(other_parts)}")

    # Join and format
    sentence = ''.join(sentence_parts)

    # Ensure proper capitalization and punctuation
    sentence = sentence[0].upper() + sentence[1:]
    if not sentence.endswith('.'):
        sentence += '.'

    return sentence

# EVOLVE-BLOCK-END
